def _hamiltonian_path_util(graph, V, path, visited, path_index):
    if path_index == V:
        return True

    current_vertex = path[path_index - 1]

    for next_vertex in range(V):
        if graph[current_vertex][next_vertex] == 1 and not visited[next_vertex]:
            path[path_index] = next_vertex
            visited[next_vertex] = True

            if _hamiltonian_path_util(graph, V, path, visited, path_index + 1):
                return True

            visited[next_vertex] = False
            path[path_index] = -1

    return False


def find_hamiltonian_path(graph):
    V = len(graph)
    path = [-1] * V

    for start_node in range(V):
        path[0] = start_node
        visited = [False] * V
        visited[start_node] = True

        if _hamiltonian_path_util(graph, V, path, visited, 1):
            return path

    return None
